<template>
    <main>
        <div class="preloader" v-if="status == 0"><b-spinner variant="primary" type="grow" label="Spinning"></b-spinner></div>
        <div class="container">
            <div class="main-wrapper">
                <orderForm :loader="status"></orderForm>
            </div>
        </div>
    </main>
</template>
<script>
import OrderForm from "@/components/order/form";
export default {
    components: {
        OrderForm
    },
    data: function(){
        return {
            status: 0
        }
    },
    beforeCreate(){
        if(this.$store.state.username == null){
            this.$store.dispatch('GET_USER_INFO');
        }   
        
        
    },
    mounted(){
        let self = this;
        // if(Object.keys(this.$store.state.products).length == 0){
            
            let basketItems = this.$store.state.basketItems;
            let collectionId = 0;

            for(let i = 0; i < basketItems.length; i++){
                let item = basketItems[i];

                collectionId = item.collectionId;
            }

            this.$store.dispatch('GET_PRODUCT_LIST', collectionId)
            .then(response => {
                self.status = 1;
             })
            .catch(err => console.log(err));
        // }
    }
}
</script>