<template>
    <form class="order-list" v-on:submit.prevent="onSubmit">
        <h1 class="main-title">ваш заказ</h1>
        <orderList :status="status"></orderList>
        <input id="send-form" type="submit" v-if="activeForm && !message" value="подтвердить">
        <div v-if="message">{{message}}</div>
    </form>
</template>
<script>
import OrderList from "@/components/order/list";
export default {
    name: 'orderForm',
    components: {
        OrderList
    },
    data: function(){
        return {
            activeForm: true,
            status: false,
            message: ""
        }
    },
    props: [
        "loader"
    ],
    methods: {
        onSubmit(){
            let self = this;
            this.message = "Обработка запроса...";
            
            this.$store.dispatch('CREATE_ORDER')
            .then(response => {
                self.$store.dispatch('CLEAR_BASKET');
                self.activeForm = false;
                self.status = false;
                self.message = "";

                self.$bvToast.toast('Заказ успешно сформирован!', {
                    title: 'Оформление заказа',
                    autoHideDelay: 3000,
                    variant: 'success',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });
             })
            .catch(err => {
                self.$bvToast.toast(err.response, {
                    title: 'Оформление заказа',
                    autoHideDelay: 3000,
                    variant: 'success',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });
                self.message = ""
            });

        }
    },
    watch: {
        loader: function(newStatus, oldStatus) {
            this.status = newStatus;
        }
    },
    mounted(){
        let self = this;

        /**
         * деактивайия кнопки, когда товаров в корзине нет
         */
        if(Object.keys(this.$store.state.basketItems).length == 0){
            this.activeForm = false;
        }
    }
}
</script>
<style lang="scss" scoped>
    .order-list{
        width: 100%;
    }
    .order-list > div{
        width: 100%;
    }
</style>